import benchmarksJson from '../data/benchmarks.json';

// ─── JSON types (mirrors the structure generated by build-benchmarks.mjs) ──────

type FractionPair = [number, number];
type CanaisPair   = { varejo: FractionPair; atacado: FractionPair };

const json = benchmarksJson as unknown as {
  _meta: { version: string; generatedAt: string; source: string };
  margemBruta: Record<string, CanaisPair>;
  remarcacao:  Record<string, FractionPair>;
  investMarketing: Array<{
    segmento: string;
    porte: string;
    posicionamento: string;
    min: number;
    max: number;
  }>;
};

// ─── Internal helpers ─────────────────────────────────────────────────────────

/** Fractions in JSON (0.50) → integer percentages used by the engine (50). */
function toPercPair(pair: FractionPair): [number, number] {
  return [Math.round(pair[0] * 100), Math.round(pair[1] * 100)];
}

/**
 * MC is not stored separately in the JSON; derive it from margemBruta by
 * subtracting the typical variable-cost load:
 *  varejo  ≈ 12 pp  (ICMS ~4 % + taxas ~3.5 % + comissões ~4.5 %)
 *  atacado ≈ 10 pp  (ICMS ~3 % + taxas ~2 % + comissões ~5 %)
 */
const MC_OFFSET_VAREJO  = 12;
const MC_OFFSET_ATACADO = 10;

function mcFromMb(mb: CanaisPair): { varejo: [number, number]; atacado: [number, number] } {
  const [vMin, vMax] = toPercPair(mb.varejo);
  const [aMin, aMax] = toPercPair(mb.atacado);
  return {
    varejo:  [Math.max(0, vMin - MC_OFFSET_VAREJO),  Math.max(0, vMax - MC_OFFSET_VAREJO)],
    atacado: [Math.max(0, aMin - MC_OFFSET_ATACADO), Math.max(0, aMax - MC_OFFSET_ATACADO)],
  };
}

// ─── Public constants (SAME names and shapes as the old hard-coded version) ───

export const ICMS_DEFAULTS = { varejo: 10, atacado: 6 };
export const CUSTO_VARIAVEL_DEFAULTS = {
  varejo:  { taxas: 3.5, comissoes: 8.0, total: 11.5 },
  atacado: { taxas: 2.0, comissoes: 5.0, total: 7.0 },
};
export const calcICMSHibrido = (percVarejo: number, percAtacado: number) =>
  (percVarejo * ICMS_DEFAULTS.varejo + percAtacado * ICMS_DEFAULTS.atacado) / 100;

export const BENCHMARK_MARGEM_BRUTA: Record<string, { varejo: [number, number]; atacado: [number, number] }> =
  Object.fromEntries(
    Object.entries(json.margemBruta).map(([k, v]) => [
      k,
      { varejo: toPercPair(v.varejo), atacado: toPercPair(v.atacado) },
    ]),
  );

export const BENCHMARK_MC: Record<string, { varejo: [number, number]; atacado: [number, number] }> =
  Object.fromEntries(
    Object.entries(json.margemBruta).map(([k, v]) => [k, mcFromMb(v)]),
  );

export const BENCHMARK_REMARCACAO: Record<string, [number, number]> =
  Object.fromEntries(
    Object.entries(json.remarcacao).map(([k, v]) => [k, toPercPair(v)]),
  );

// ─── Marketing investment benchmark (new in PASSO 5) ─────────────────────────

export interface InvestMktRecord {
  segmento: string;
  porte: string;
  posicionamento: string;
  min: number; // fraction  0.04 = 4 %
  max: number;
}

export const BENCHMARK_INVEST_MKT: InvestMktRecord[] = json.investMarketing;

/**
 * Returns the suggested invest-in-marketing range as a [min, max] **percentage**
 * (e.g. [4, 10] means 4 %–10 % of revenue).
 *
 * Lookup priority:
 *  1. segmento + porte + posicionamento (exact)
 *  2. segmento + porte  (any posicionamento)
 *  3. segmento          (any porte/posicionamento)
 *  4. hard fallback     [4, 10]
 */
export function getInvestMktBenchmark(
  segmento: string,
  porte?: string,
  posicionamento?: string,
): [number, number] {
  const records = BENCHMARK_INVEST_MKT.filter(r => r.segmento === segmento);
  if (!records.length) return [4, 10];

  const byPorte = porte ? records.filter(r => r.porte === porte) : [];
  const byFull  = posicionamento ? byPorte.filter(r => r.posicionamento === posicionamento) : [];

  const pool = byFull.length ? byFull : byPorte.length ? byPorte : records;

  return [
    Math.round(Math.min(...pool.map(r => r.min)) * 100),
    Math.round(Math.max(...pool.map(r => r.max)) * 100),
  ];
}

// ─── Unchanged generic helpers ────────────────────────────────────────────────

export const getBenchmark = (obj: Record<string, any>, segmento: string, modelo?: string, porte?: string): [number, number] => {
  const seg = obj[segmento] ?? obj['default'];
  if (typeof seg === 'object' && !Array.isArray(seg)) {
    const canal = seg[modelo || 'varejo'] ?? seg['varejo'];
    if (porte && canal && typeof canal === 'object' && !Array.isArray(canal) && canal[porte]) {
      return canal[porte];
    }
    return canal;
  }
  return seg;
};

